using UnityEngine;
using UnityEngine.UI;
using System;
using System.Collections.Generic;

public class PlayerStats : MonoBehaviour
{
    public int playerHealth = 100;
    public int playerMaxHealth = 100;
    public int playerCurrency = 0;
    public int playerDamage = 10;

    public void TakeDamage(int amount)
    {
        int finalDamage = Mathf.Max(0, amount);
        playerHealth = Mathf.Max(0, playerHealth - finalDamage);
    }

    public void Heal(int amount)
    {
        int finalHeal = Mathf.Max(0, amount);
        playerHealth = Mathf.Min(playerMaxHealth, playerHealth + finalHeal);
    }

    public void AddCurrency(int amount)
    {
        playerCurrency = Mathf.Max(0, playerCurrency + amount);
    }

    public bool SpendCurrency(int amount)
    {
        if (amount < 0) return false;
        if (playerCurrency < amount) return false;
        playerCurrency -= amount;
        return true;
    }

    public void IncreaseDamage(int amount)
    {
        playerDamage = Mathf.Max(0, playerDamage + amount);
    }
}

[Serializable]
public class ShopItem
{
    public string itemId;
    public string itemName;
    public int basePrice = 100;
    public float priceMultiplier = 1.15f;
    public int baseDamageBonus = 0;
    public int baseHealAmount = 0;
    public int purchasedCount = 0;

    public int GetCurrentPrice()
    {
        return Mathf.CeilToInt(basePrice * Mathf.Pow(priceMultiplier, purchasedCount));
    }

    public int GetCurrentDamageBonus()
    {
        return baseDamageBonus + purchasedCount;
    }

    public int GetCurrentHealAmount()
    {
        return baseHealAmount + purchasedCount * 5;
    }
}

public class ShopManager : MonoBehaviour
{
    public PlayerStats playerStats;
    public List<ShopItem> items = new List<ShopItem>();

    public Text currencyText;
    public Text healthText;
    public Text damageText;
    public Text shopMessageText;

    private void Start()
    {
        RefreshUI();
    }

    public void PurchaseItem(int itemIndex)
    {
        if (playerStats == null) return;
        if (itemIndex < 0 || itemIndex >= items.Count) return;

        ShopItem item = items[itemIndex];
        int price = item.GetCurrentPrice();

        if (!playerStats.SpendCurrency(price))
        {
            SetMessage("Not enough currency.");
            RefreshUI();
            return;
        }

        if (item.baseDamageBonus > 0)
        {
            int bonus = item.GetCurrentDamageBonus();
            playerStats.IncreaseDamage(bonus);
        }

        if (item.baseHealAmount > 0)
        {
            int heal = item.GetCurrentHealAmount();
            playerStats.Heal(heal);
        }

        item.purchasedCount++;
        SetMessage(item.itemName + " purchased.");
        RefreshUI();
    }

    public int CalculateDamage(int baseDamage, float damageMultiplier, int flatBonus)
    {
        int calculated = Mathf.RoundToInt(baseDamage * damageMultiplier) + flatBonus;
        return Mathf.Max(0, calculated);
    }

    public void ApplyDamageToPlayer(int baseDamage, float damageMultiplier, int flatBonus)
    {
        int finalDamage = CalculateDamage(baseDamage, damageMultiplier, flatBonus);
        playerStats.TakeDamage(finalDamage);
        RefreshUI();
    }

    public void RefreshUI()
    {
        if (playerStats == null) return;

        if (currencyText != null) currencyText.text = "Currency: " + playerStats.playerCurrency;
        if (healthText != null) healthText.text = "Health: " + playerStats.playerHealth + "/" + playerStats.playerMaxHealth;
        if (damageText != null) damageText.text = "Damage: " + playerStats.playerDamage;
    }

    private void SetMessage(string message)
    {
        if (shopMessageText != null) shopMessageText.text = message;
    }
}

